# ── BANCO ──────────────────────────────────────────────────
def conectar_banco():
    url = st.secrets["supabase"]["url"]
    conn = psycopg2.connect(url); conn.autocommit = False; return conn

def hash_senha(s): return hashlib.sha256(s.encode()).hexdigest()

def inicializar_banco_de_dados():
    conn = conectar_banco(); cursor = conn.cursor()
    cursor.execute("""CREATE TABLE IF NOT EXISTS cronograma_macro (
        id SERIAL PRIMARY KEY, Obra TEXT, EDT TEXT UNIQUE, Tipo_Escopo TEXT, Etapa_Macro TEXT,
        Subdivisao TEXT, Tarefa TEXT, M2_Total_Tarefa REAL, Inicio_Previsto DATE, Termino_Obra DATE,
        Status TEXT DEFAULT 'Pendente', Status_Engenharia TEXT DEFAULT 'Aguardando Medicao In Loco',
        Prazo_Engenharia DATE, Data_Limite_Despacho DATE, Primeiro_Dia_Producao DATE)""")
    cursor.execute("""CREATE TABLE IF NOT EXISTS itens_detalhado (
        id SERIAL PRIMARY KEY, Obra_Vinculada TEXT, EDT_Vinculado TEXT, Cod_Lote TEXT, Num_OP TEXT,
        Tipo_Material TEXT, Qtd_Caixas INTEGER, M2_Item REAL, Data_Producao_Programada DATE,
        Data_Limite_Obra DATE, Data_Despacho DATE, Romaneio_Chapas TEXT,
        Status_Item TEXT DEFAULT 'Pendente', Dificuldade INTEGER DEFAULT 3,
        Fase_Produtiva TEXT, Enviado_Logistica INTEGER DEFAULT 0)""")
    cursor.execute("""CREATE TABLE IF NOT EXISTS usuarios (
        id SERIAL PRIMARY KEY, usuario TEXT UNIQUE, nome TEXT, setor TEXT, senha TEXT)""")
    cursor.execute("""CREATE TABLE IF NOT EXISTS solicitacoes_prazo (
        id SERIAL PRIMARY KEY, edt TEXT, tarefa TEXT, prazo_atual TEXT, prazo_solicitado TEXT,
        justificativa TEXT, criado_por TEXT, status TEXT DEFAULT 'Pendente de Aprovacao', criado_em TEXT)""")
    cursor.execute("""CREATE TABLE IF NOT EXISTS logistica_envios (
        id SERIAL PRIMARY KEY, item_id INTEGER, Obra_Vinculada TEXT, EDT_Vinculado TEXT,
        Cod_Lote TEXT, Num_OP TEXT, Tipo_Material TEXT, Qtd_Caixas INTEGER, M2_Item REAL,
        Romaneio_Chapas TEXT, Data_Limite_Despacho DATE, Data_Envio_Agendado DATE,
        Transportadora TEXT, Veiculo TEXT, Observacoes TEXT,
        Status_Logistica TEXT DEFAULT 'Aguardando Agendamento', Confirmado_Por TEXT, Confirmado_Em TEXT)""")
    cursor.execute("SELECT COUNT(*) FROM usuarios")
    if cursor.fetchone()[0] == 0:
        cursor.execute("INSERT INTO usuarios (usuario,nome,setor,senha) VALUES (%s,%s,%s,%s)",
                       ('master','Joice Master','Master',hash_senha('Jv568279.')))
    conn.commit(); conn.close()

inicializar_banco_de_dados()

# ── UTILITÁRIOS ────────────────────────────────────────────
def subtrair_dias_uteis(data_base, n):
    data = data_base; contados = 0
    while contados < n:
        data -= timedelta(days=1)
        if data.weekday() < 5: contados += 1
    return data

def prazo_valido(valor):
    if valor is None: return False
    try: return not pd.isnull(valor)
    except: return False

def gerar_lote_unico(data_limite_obra, dias_logistica, dias_uteis_fab, total_cx, total_m2,
                     obra, edt, cod_lote, especificacao, txt_pav, dificuldade):
    dt_limite   = datetime.combine(data_limite_obra, datetime.min.time()) if not isinstance(data_limite_obra, datetime) else data_limite_obra
    dt_despacho = dt_limite - timedelta(days=int(dias_logistica))
    dt_inicio   = subtrair_dias_uteis(dt_despacho, int(dias_uteis_fab))
    return [{"Obra_Vinculada":obra,"EDT_Vinculado":edt,"Cod_Lote":cod_lote,"Num_OP":None,
             "Tipo_Material":especificacao,"Qtd_Caixas":int(total_cx),"M2_Item":float(round(total_m2,2)),
             "Data_Producao_Programada":dt_inicio.strftime('%Y-%m-%d'),
             "Data_Limite_Obra":dt_limite.strftime('%Y-%m-%d'),
             "Data_Despacho":dt_despacho.strftime('%Y-%m-%d'),
             "Romaneio_Chapas":txt_pav,"Status_Item":"Pendente","Dificuldade":int(dificuldade),
             "Fase_Produtiva":f"CORTE→MONTAGEM ({dias_uteis_fab} dias uteis)","Enviado_Logistica":0}]

# ── QUERIES ────────────────────────────────────────────────
def carregar_macro():
    conn = conectar_banco()
    df = pd.read_sql_query("SELECT * FROM cronograma_macro ORDER BY id", conn); conn.close()
    for col in ['inicio_previsto','termino_obra','prazo_engenharia','data_limite_despacho','primeiro_dia_producao']:
        if col in df.columns: df[col] = pd.to_datetime(df[col], errors='coerce')
    df.columns = [c.replace('_',' ').title().replace(' ','_') if c != 'id' else c for c in df.columns]
    df = df.rename(columns={'Edt':'EDT','Num_Op':'Num_OP'})
    return df

def carregar_micro():
    conn = conectar_banco()
    df = pd.read_sql_query("SELECT * FROM itens_detalhado ORDER BY Data_Producao_Programada ASC", conn); conn.close()
    for col in ['data_producao_programada','data_limite_obra']:
        if col in df.columns: df[col] = pd.to_datetime(df[col], errors='coerce')
    df.columns = [c.replace('_',' ').title().replace(' ','_') if c != 'id' else c for c in df.columns]
    df = df.rename(columns={'Edt_Vinculado':'EDT_Vinculado','Num_Op':'Num_OP'})
    return df

def carregar_fila_logistica():
    conn = conectar_banco()
    df = pd.read_sql_query("SELECT * FROM logistica_envios ORDER BY data_limite_despacho ASC NULLS LAST", conn); conn.close()
    for col in ['data_limite_despacho','data_envio_agendado']:
        if col in df.columns: df[col] = pd.to_datetime(df[col], errors='coerce')
    df.columns = [c.replace('_',' ').title().replace(' ','_') if c != 'id' else c for c in df.columns]
    df = df.rename(columns={'Edt_Vinculado':'EDT_Vinculado','Num_Op':'Num_OP','Item_Id':'item_id'})
    return df

def carregar_solicitacoes():
    conn = conectar_banco()
    df = pd.read_sql_query("SELECT * FROM solicitacoes_prazo ORDER BY id DESC", conn); conn.close()
    return df

def salvar_lotes_micro(lotes):
    if not lotes: return
    conn = conectar_banco(); cursor = conn.cursor()
    for l in lotes:
        cursor.execute("""INSERT INTO itens_detalhado
            (Obra_Vinculada,EDT_Vinculado,Cod_Lote,Num_OP,Tipo_Material,Qtd_Caixas,M2_Item,
             Data_Producao_Programada,Data_Limite_Obra,Romaneio_Chapas,Status_Item,Dificuldade,Fase_Produtiva,Enviado_Logistica)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
            (l['Obra_Vinculada'],l['EDT_Vinculado'],l['Cod_Lote'],l['Num_OP'],l['Tipo_Material'],
             l['Qtd_Caixas'],l['M2_Item'],l['Data_Producao_Programada'],l['Data_Limite_Obra'],
             l['Romaneio_Chapas'],l['Status_Item'],l['Dificuldade'],l['Fase_Produtiva'],l['Enviado_Logistica']))
    conn.commit(); conn.close()

def deletar_lotes_por_edt_lote(obra, edt, cod_lote):
    conn = conectar_banco(); cursor = conn.cursor()
    if edt: cursor.execute("DELETE FROM itens_detalhado WHERE Obra_Vinculada=%s AND EDT_Vinculado=%s AND Cod_Lote=%s",(obra,edt,cod_lote))
    else:   cursor.execute("DELETE FROM itens_detalhado WHERE Obra_Vinculada=%s AND Cod_Lote=%s",(obra,cod_lote))
    conn.commit(); conn.close()

def atualizar_cronograma_macro_datas(edt, prazo_eng, primeiro_prod, despacho):
    conn = conectar_banco(); cursor = conn.cursor()
    cursor.execute("SELECT prazo_engenharia,primeiro_dia_producao,data_limite_despacho FROM cronograma_macro WHERE EDT=%s",(edt,))
    row = cursor.fetchone()
    def to_dt(v):
        try: return pd.to_datetime(v) if v else None
        except: return None
    if row:
        pa,pp,pd_ = to_dt(row[0]),to_dt(row[1]),to_dt(row[2])
        np_ = min(pa,  pd.to_datetime(prazo_eng))    if pa  else pd.to_datetime(prazo_eng)
        npp = min(pp,  pd.to_datetime(primeiro_prod)) if pp  else pd.to_datetime(primeiro_prod)
        nd  = min(pd_, pd.to_datetime(despacho))     if pd_ else pd.to_datetime(despacho)
    else:
        np_=pd.to_datetime(prazo_eng); npp=pd.to_datetime(primeiro_prod); nd=pd.to_datetime(despacho)
    cursor.execute("UPDATE cronograma_macro SET Prazo_Engenharia=%s,Primeiro_Dia_Producao=%s,Data_Limite_Despacho=%s WHERE EDT=%s",
                   (np_.strftime('%Y-%m-%d'),npp.strftime('%Y-%m-%d'),nd.strftime('%Y-%m-%d'),edt))
    conn.commit(); conn.close()

def atualizar_status_engenharia(edt_id, novo_status):
    conn = conectar_banco(); cursor = conn.cursor()
    cursor.execute("UPDATE cronograma_macro SET Status_Engenharia=%s WHERE id=%s",(novo_status,edt_id))
    conn.commit(); conn.close()

